// MARK: - Encryption Errors

enum DataSecurityError: Error, LocalizedError {
    case keyGenerationFailed
    case keychainSaveFailed(OSStatus)
    case keychainReadFailed
    case encryptionFailed(CCCryptorStatus)
    case decryptionFailed(CCCryptorStatus)
    case invalidData
    case ivGenerationFailed
    case dataIntegrityCheckFailed
    
    var errorDescription: String? {
        switch self {
        case .keyGenerationFailed: return "Failed to generate encryption key"
        case .keychainSaveFailed(let status): return "Keychain save failed with status: \(status)"
        case .keychainReadFailed: return "Failed to read key from Keychain"
        case .encryptionFailed(let status): return "Encryption failed with status: \(status)"
        case .decryptionFailed(let status): return "Decryption failed with status: \(status)"
        case .invalidData: return "Invalid data provided"
        case .ivGenerationFailed: return "Failed to generate initialization vector"
        case .dataIntegrityCheckFailed: return "Data integrity check failed - possible tampering"
        }
    }
}

