// MARK: - Keychain Manager

final class KeychainManager {
    
    static let shared = KeychainManager()
    
    private let keychainServiceIdentifier = "com.app.datasecurity.encryptionkey"
    private let keychainAccount = "aes256-master-key"
    
    private init() {}
    
    func retrieveOrGenerateKey() throws -> Data {
        if let existingKey = try? retrieveKey() {
            return existingKey
        }
        
        let newKey = try generateRandomKey()
        try saveKey(newKey)
        return newKey
    }
    
    private func generateRandomKey() throws -> Data {
        var keyData = Data(count: kCCKeySizeAES256)
        let result = keyData.withUnsafeMutableBytes { bytes in
            SecRandomCopyBytes(kSecRandomDefault, kCCKeySizeAES256, bytes.baseAddress!)
        }
        guard result == errSecSuccess else {
            throw DataSecurityError.keyGenerationFailed
        }
        return keyData
    }
    
    private func saveKey(_ key: Data) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainServiceIdentifier,
            kSecAttrAccount as String: keychainAccount,
            kSecValueData as String: key,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        // Delete existing key if present
        SecItemDelete(query as CFDictionary)
        
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw DataSecurityError.keychainSaveFailed(status)
        }
    }
    
    private func retrieveKey() throws -> Data {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainServiceIdentifier,
            kSecAttrAccount as String: keychainAccount,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let keyData = result as? Data else {
            throw DataSecurityError.keychainReadFailed
        }
        
        return keyData
    }
    
    func deleteKey() {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainServiceIdentifier,
            kSecAttrAccount as String: keychainAccount
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - AES Encryption Engine

final class AESEncryptionEngine {
    
    private let keySize = kCCKeySizeAES256
    private let blockSize = kCCBlockSizeAES128
    private let algorithm = CCAlgorithm(kCCAlgorithmAES)
    private let options = CCOptions(kCCOptionPKCS7Padding)
    
    func encrypt(data: Data, key: Data) throws -> Data {
        // Generate random IV
        var iv = Data(count: blockSize)
        let ivResult = iv.withUnsafeMutableBytes { bytes in
            SecRandomCopyBytes(kSecRandomDefault, blockSize, bytes.baseAddress!)
        }
        guard ivResult == errSecSuccess else {
            throw DataSecurityError.ivGenerationFailed
        }
        
        let encrypted = try performCrypt(
            operation: CCOperation(kCCEncrypt),
            data: data,
            key: key,
            iv: iv
        )
        
        // Prepend IV to encrypted data: [IV (16 bytes)][Encrypted Data][HMAC (32 bytes)]
        var combined = iv
        combined.append(encrypted)
        
        // Append HMAC for integrity verification
        let hmac = computeHMAC(data: combined, key: key)
        combined.append(hmac)
        
        return combined
    }
    
    func decrypt(data: Data, key: Data) throws -> Data {
        let hmacLength = Int(CC_SHA256_DIGEST_LENGTH)
        
        guard data.count > blockSize + hmacLength else {
            throw DataSecurityError.invalidData
        }
        
        // Extract components
        let hmacStart = data.count - hmacLength
        let ivAndEncrypted = data.prefix(hmacStart)
        let storedHMAC = data.suffix(hmacLength)
        
        // Verify HMAC integrity
        let computedHMAC = computeHMAC(data: ivAndEncrypted, key: key)
        guard constantTimeCompare(Data(storedHMAC), computedHMAC) else {
            throw DataSecurityError.dataIntegrityCheckFailed
        }
        
        let iv = ivAndEncrypted.prefix(blockSize)
        let encryptedData = ivAndEncrypted.dropFirst(blockSize)
        
        return try performCrypt(
            operation: CCOperation(kCCDecrypt),
            data: Data(encryptedData),
            key: key,
            iv: Data(iv)
        )
    }
    
    private func performCrypt(operation: CCOperation, data: Data, key: Data, iv: Data) throws -> Data {
        let outputLength = data.count + blockSize
        var outputData = Data(count: outputLength)
        var bytesWritten: Int = 0
        
        let status = outputData.withUnsafeMutableBytes { outputBytes in
            data.withUnsafeBytes { dataBytes in
                key.withUnsafeBytes { keyBytes in
                    iv.withUnsafeBytes { ivBytes in
                        CCCrypt(
                            operation,
                            algorithm,
                            options,
                            keyBytes.baseAddress!,
                            keySize,
                            ivBytes.baseAddress!,
                            dataBytes.baseAddress!,
                            data.count,
                            outputBytes.baseAddress!,
                            outputLength,
                            &bytesWritten
                        )
                    }
                }
            }
        }
        
        guard status == kCCSuccess else {
            if operation == CCOperation(kCCEncrypt) {
                throw DataSecurityError.encryptionFailed(status)
            } else {
                throw DataSecurityError.decryptionFailed(status)
            }
        }
        
        outputData.removeSubrange(bytesWritten..<outputData.count)
        return outputData
    }
    
    private func computeHMAC(data: Data, key: Data) -> Data {
        var hmac = Data(count: Int(CC_SHA256_DIGEST_LENGTH))
        hmac.withUnsafeMutableBytes { hmacBytes in
            data.withUnsafeBytes { dataBytes in
                key.withUnsafeBytes { keyBytes in
                    CCHmac(
                        CCHmacAlgorithm(kCCHmacAlgSHA256),
                        keyBytes.baseAddress!,
                        key.count,
                        dataBytes.baseAddress!,
                        data.count,
                        hmacBytes.baseAddress!
                    )
                }
            }
        }
        return hmac
    }
    
    /// Constant-time comparison to prevent timing attacks
    private func constantTimeCompare(_ a: Data, _ b: Data) -> Bool {
        guard a.count == b.count else { return false }
        var result: UInt8 = 0
        for (byteA, byteB) in zip(a, b) {
            result |= byteA ^ byteB
        }
        return result == 0
    }
}

// MARK: - Secure Storage Manager

final class SecureStorageManager {
    
    private let fileManager = FileManager.default
    private let encryptionEngine = AESEncryptionEngine()
    private let keychainManager = KeychainManager.shared
    private let encoder = JSONEncoder()
    private let decoder = JSONDecoder()
    
    private var encryptionKey: Data?
    
    private lazy var secureDirectory: URL = {
        let documentsDir = fileManager.urls(for: .applicationSupportDirectory, in: .userDomainMask).first!
        let secureDir = documentsDir.appendingPathComponent("SecureStore", isDirectory: true)
        if !fileManager.fileExists(atPath: secureDir.path) {
            try? fileManager.createDirectory(at: secureDir, withIntermediateDirectories: true)
        }
        // Exclude from backups
        var resourceValues = URLResourceValues()
        resourceValues.isExcludedFromBackup = true
        var mutableDir = secureDir
        try? mutableDir.setResourceValues(resourceValues)
        return secureDir
    }()
    
    init() {
        encoder.dateEncodingStrategy = .iso8601
        decoder.dateDecodingStrategy = .iso8601
    }
    
    private func getKey() throws -> Data {
        if let key = encryptionKey {
            return key
        }
        let key = try keychainManager.retrieveOrGenerateKey()
        encryptionKey = key
        return key
    }
    
    private func fileURL(for identifier: String) -> URL {
        return secureDirectory.appendingPathComponent(identifier.sha256Hash + ".encrypted")
    }
    
    // MARK: - Generic Encrypt & Store
    
    func encryptAndStore<T: Codable>(_ object: T, identifier: String) throws {
        let key = try getKey()
        let jsonData = try encoder.encode(object)
        let encryptedData = try encryptionEngine.encrypt(data: jsonData, key: key)
        
        let url = fileURL(for: identifier)
        try encryptedData.write(to: url, options: [.atomic, .completeFileProtection])
    }
    
    func retrieveAndDecrypt<T: Codable>(_ type: T.Type, identifier: String) throws -> T {
        let key = try getKey()
        let url = fileURL(for: identifier)
        
        guard fileManager.fileExists(atPath: url.path) else {
            throw DataSecurityError.invalidData
        }
        
        let encryptedData = try Data(contentsOf: url)
        let decryptedData = try encryptionEngine.decrypt(data: encryptedData, key: key)
        return try decoder.decode(T.self, from: decryptedData)
    }
    
    func deleteSecureData(identifier: String) throws {
        let url = fileURL(for: identifier)
        if fileManager.fileExists(atPath: url.path) {
            try fileManager.removeItem(at: url)
        }
    }
    
    func secureDataExists(identifier: String) -> Bool {
        let url = fileURL(for: identifier)
        return fileManager.fileExists(atPath: url.path)
    }
    
    // MARK: - Raw Data Encryption
    
    func encryptRawData(_ data: Data) throws -> Data {
        let key = try getKey()
        return try encryptionEngine.encrypt(data: data, key: key)
    }
    
    func decryptRawData(_ data: Data) throws -> Data {
        let key = try getKey()
        return try encryptionEngine.decrypt(data: data, key: key)
    }
    
    // MARK: - String Encryption
    
    func encryptString(_ string: String) throws -> Data {
        guard let data = string.data(using: .utf8) else {
            throw DataSecurityError.invalidData
        }
        return try encryptRawData(data)
    }
    
    func decryptString(_ encryptedData: Data) throws -> String {
        let decryptedData = try decryptRawData(encryptedData)
        guard let string = String(data: decryptedData, encoding: .utf8) else {
            throw DataSecurityError.invalidData
        }
        return string
    }
    
    // MARK: - Wipe All Secure Data
    
    func wipeAllSecureData() throws {
        if fileManager.fileExists(atPath: secureDirectory.path) {
            let contents = try fileManager.contentsOfDirectory(
                at: secureDirectory,
                includingPropertiesForKeys: nil
            )
            for fileURL in contents {
                try fileManager.removeItem(at: fileURL)
            }
        }
        keychainManager.deleteKey()
        encryptionKey = nil
    }
}

// MARK: - String SHA256 Helper

private extension String {
    var sha256Hash: String {
        guard let data = self.data(using: .utf8) else { return self }
        var hash = Data(count: Int(CC_SHA256_DIGEST_LENGTH))
        hash.withUnsafeMutableBytes { hashBytes in
            data.withUnsafeBytes { dataBytes in
                _ = CC_SHA256(dataBytes.baseAddress!, CC_LONG(data.count), hashBytes.bindMemory(to: UInt8.self).baseAddress!)
            }
        }
        return hash.map { String(format: "%02x", $0) }.joined()
    }
}

// MARK: - Data Security Module (High-Level API)

final class DataSecurityModule {
    
    static let shared = DataSecurityModule()
    
    private let storage = SecureStorageManager()
    
    private enum StorageKey {
        static let userCredentials = "user_credentials"
        static let paymentTokenPrefix = "payment_token_"
        static let personalInfo = "personal_information"
    }
    
    private init() {}
    
    // MARK: - User Credentials
    
    func storeCredentials(_ credentials: UserCredentials) throws {
        try storage.encryptAndStore(credentials, identifier: StorageKey.userCredentials)
    }
    
    func retrieveCredentials() throws -> UserCredentials {
        return try storage.retrieveAndDecrypt(UserCredentials.self, identifier: StorageKey.userCredentials)
    }
    
    func deleteCredentials() throws {
        try storage.deleteSecureData(identifier: StorageKey.userCredentials)
    }
    
    func hasStoredCredentials() -> Bool {
        return storage.secureDataExists(identifier: StorageKey.userCredentials)
    }
    
    // MARK: - Payment Tokens
    
    func storePaymentToken(_ token: PaymentToken) throws {
        let identifier = StorageKey.paymentTokenPrefix + token.tokenId
        try storage.encryptAndStore(token, identifier: identifier)
        
        // Maintain a list of stored token IDs
        var tokenIds = (try? retrieveTokenIdList()) ?? []
        if !tokenIds.contains(token.tokenId) {
            tokenIds.append(token.tokenId)
            try storage.encryptAndStore(tokenIds, identifier: "payment_token_list")
        }
    }
    
    func retrievePaymentToken(tokenId: String) throws -> PaymentToken {
        let identifier = StorageKey.paymentTokenPrefix + tokenId
        return try storage.retrieveAndDecrypt(PaymentToken.self, identifier: identifier)
    }
    
    func retrieveAllPaymentTokens() throws -> [PaymentToken] {
        let tokenIds = try retrieveTokenIdList()
        return tokenIds.compactMap { try? retrievePaymentToken(tokenId: $0) }
    }
    
    func deletePaymentToken(tokenId: String) throws {
        let identifier = StorageKey.paymentTokenPrefix + tokenId
        try storage.deleteSecureData(identifier: identifier)
        
        var tokenIds = (try? retrieveTokenIdList()) ?? []
        tokenIds.removeAll { $0 == tokenId }
        try storage.encryptAndStore(tokenIds, identifier: "payment_token_list")
    }
    
    private func retrieveTokenIdList() throws -> [String] {
        return try storage.retrieveAndDecrypt([String].self, identifier: "payment_token_list")
    }
    
    // MARK: - Personal Information
    
    func storePersonalInfo(_ info: PersonalInformation) throws {
        try storage.encryptAndStore(info, identifier: StorageKey.personalInfo)
    }
    
    func retrievePersonalInfo() throws -> PersonalInformation {
        return try storage.retrieveAndDecrypt(PersonalInformation.self, identifier: StorageKey.personalInfo)
    }
    
    func deletePersonalInfo() throws {
        try storage.deleteSecureData(identifier: StorageKey.personalInfo)
    }
    
    func hasStoredPersonalInfo() -> Bool {
        return storage.secureDataExists(identifier: StorageKey.personalInfo)
    }
    
    // MARK: - Generic Secure Storage
    
    func storeSecurely<T: Codable>(_ object: T, withKey key: String) throws {
        try storage.encryptAndStore(object, identifier: key)
    }
    
    func retrieveSecurely<T: Codable>(_ type: T.Type, withKey key: String) throws -> T {
        return try storage.retrieveAndDecrypt(type, identifier: key)
    }
    
    func deleteSecurely(key: String) throws {
        try storage.deleteSecureData(identifier: key)
    }
    
    // MARK: - Secure String Operations
    
    func encryptSensitiveString(_ string: String) throws -> Data {
        return try storage.encryptString(string)
    }
    
    func decryptSensitiveString(_ encryptedData: Data) throws -> String {
        return try storage.decryptString(encryptedData)
    }
    
    // MARK: - Complete Data Wipe
    
    func performSecureWipe() throws {
        try storage.wipeAllSecureData()
    }
}

